		function Filtrar()
{ 
 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay CVs filtradas.");
 		return false;
 	}

 	if (Ctrl("list2").TotalRowsCount()>100)
 	{             
 		alert("Hay demasiados registros seleccionados, afine la búsqueda.");
 		return false;
 	}
	SendToServer();
	Ctrl("main").DoEvent("FILTER");
}


function hiddenedad()
{   
  var ed = Ctrl('edad_desde').GetXValue();
  var eh = Ctrl('edad_hasta').GetXValue();

  var a = new Date();
  a.setFullYear(a.getFullYear()-eh);
  a = datetime2str(a);
  var b = new Date();
  b.setFullYear(b.getFullYear()-ed);
  b = datetime2str(b);

  Ctrl('h_edad_desde').SetXValue('');
  Ctrl('h_edad_hasta').SetXValue('');

  if(ed!="")
  {
    Ctrl('h_edad_desde').SetXValue(a);
  }
  if(eh!="")
  {
    Ctrl('h_edad_hasta').SetXValue(b);
  }   

}

var arrA, arrB;


//Ejecuta el Query Seleccionado y devuelve un ARRAY con el resultado
function exec_qry()
{	
	var np, nSQL, i;

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	//var qry = Ctrl("main").getResource("qry_" + Ctrl("tab_filtro").GetSelectedPanelID());
	//tira un unico qry con todos los filtros    
	var cant_reg = Ctrl("main").getResource("qry_count");   
	var qryMembers = cant_reg.split("##");

	for (i=1; i<qryMembers.length; i+=2)
	{  
		if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
		{
			alert("El valor es requerido");
			Ctrl(qryMembers[i]).SetFocus();
			return null;
		}	
	qryMembers[i]=Ctrl(qryMembers[i]).GetXValue();	
	} 

  cant_reg = qryMembers.join("");       

  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(cant_reg);
  var result = nSQL.GetXML(cant_reg, "");

	var count = result.GetAttr("cant_reg");

	if (count < 500) {
	var qry = Ctrl("main").getResource("qry_cv");

	qryMembers = qry.split("##");

	for (i=1; i<qryMembers.length; i+=2)
	{  
		if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
		{
			alert("El valor es requerido");
			Ctrl(qryMembers[i]).SetFocus();
			return null;
		}	
	qryMembers[i]=Ctrl(qryMembers[i]).GetXValue();
	}

  qry = qryMembers.join("");       

  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(qry);
  var result = nSQL.Get(qry, "");

 	var resultArray = string2array(result);

 	if (Ctrl("main").getResource("qry_externo"))
 	{
 		qry = Ctrl("main").getResource("qry_externo");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=Ctrl(qryMembers[i]).GetXValue();
		}

	  qry = qryMembers.join("");
	  result = nSQL.Get(qry, "");

	  var auxResult = string2array(result);
	  intersect(resultArray, auxResult);
	} 	

  return resultArray; 
  }
  else 
   alert("El resultado devolvió demasiados registros (Máx 500 registros). Afine la busqueda.");
}

function init_qry(strxml)
{
	var np, nSQL, result;

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	var qry = Ctrl("main").getResource("qry");
  var result = nSQL.Get(qry, strxml);
 	var resultArray = string2array(result);

  return resultArray;
}

//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{
	var key;
	for (key in arrayB)
		arrayA[key]=arrayB[key];
}

//Elimina del Array A los elementos del Array B
function remove(arrayA, arrayB)
{
	var key;
	for (key in arrayB)
		if (arrayA[key])
			delete arrayA[key];
}

//Elimina del Array A los elementos que no estan en el Array B
function intersect(arrayA, arrayB)
{
	var key;
	for (key in arrayA)
		if (arrayB[key]?false:true)
			delete arrayA[key];
}

//Transforma un Array a un XML(tipo STRING)
function array2string(arr)
{
	var retval = "";
	var key;
	for (key in arr)
	{
		retval+=ELE2String(arr[key].associatedELE);
	}

	return "<ROWS>"+retval+"</ROWS>";
}


function array2stringcustom(arr, eleroot, elechild)
{
	var key;
	var str ="<"+eleroot+">";
	for (key in arr) str+='<'+elechild+' id="'+key.substr(1)+'" />';
	str+="</"+eleroot+">";
	return str;
}              


//Transaforma un XML(tipo STRING) en ARRAY
function string2array(str)
{
	var arr = new Array();
	var auxXml = new nomadDOM(str);

	for (i=0; i<auxXml.Child.length; i++)
	{
		arr["k" + auxXml.Child[i].id]=auxXml.Child[i];
	}
	return arr;
}

//Function para activar y desactivar Botones
function enable_buttons()
{                                                                 
	if (Ctrl("list1"))
	{
		CtrlEnabled("DEL"    , Ctrl("list1").TotalRowsCount()?true:false);
		CtrlEnabled("DEL_ALL", Ctrl("list1").TotalRowsCount()?true:false);

		CtrlEnabled("list1_Clear" , Ctrl("list1").TotalRowsCount()?true:false);
		CtrlEnabled("list1_Delete", Ctrl("list1").TotalRowsCount()?true:false);
		CtrlEnabled("list1_UnMark", Ctrl("list1").TotalRowsCount()?true:false);
	}
	if (Ctrl("list2"))
	{
		CtrlEnabled("ADD"    , Ctrl("list2").TotalRowsCount()?true:false);
		CtrlEnabled("ADD_ALL", Ctrl("list2").TotalRowsCount()?true:false);

		CtrlEnabled("list2_Clear" , Ctrl("list2").TotalRowsCount()?true:false);
		CtrlEnabled("list2_Delete", Ctrl("list2").TotalRowsCount()?true:false);
		CtrlEnabled("list2_UnMark", Ctrl("list2").TotalRowsCount()?true:false);
	}
	enable_custom_buttons();
}

function enable_custom_buttons()
{
}

//Actualiza la lista con el nuevo ARRAY
function refreshList(strList, arr)
{
	Ctrl(strList).processResult(array2string(arr));
	enable_buttons();
}

function load()    { NomadTimeout("internal_load();",100,"Cargando la Lista..."); }
function filter()  { //NomadTimeout("internal_filter();",100,"Filtrando la Lista..."); 
}
function loadadd() { NomadTimeout("internal_loadadd();",100,"Agregando en la Lista..."); }        
function find()    { //NomadTimeout("internal_find();",100,"Buscando en la lista..."); 
}        

function internal_load()
{ 
  hiddenedad();  
  var auxArr;  
	auxArr = exec_qry();	
	if (auxArr==null)	
	 return;
	arrB = auxArr; 
	remove(arrB, arrA);	
	refreshList("list2", arrB);
}

function internal_filter()
{
  hiddenedad();
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	intersect(arrB, auxArr);	
	refreshList("list2", arrB);
}

function internal_loadadd()
{
  hiddenedad();
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	remove(auxArr, arrA);		
	union(arrB, auxArr);
	refreshList("list2", arrB);
}

function internal_find()
{
  hiddenedad();
  var auxArr;
  var key;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	intersect(auxArr, arrB);
	key="";
	for (key in auxArr) break;
	if (key!="") 
		Ctrl("list2").SetXValue(key.substr(1));
	else
		alert("No se encontro ningun registro.");
}

function ONLOAD()
{
	arrA = new Array();
	arrB = new Array();
	enable_buttons();     


	if (Ctrl("main").GetLastDoc("ARRA"))
	{                                  

		arrA=init_qry(ELE2String(Ctrl("main").GetLastDoc("ARRA")));

		refreshList("list1", arrA);
	}

	if (Ctrl("main").GetLastDoc("ARRB"))
	{                               

		arrB=init_qry(ELE2String(Ctrl("main").GetLastDoc("ARRB")));

		refreshList("list2", arrB);
	}
}        


function ADD_ALL() { NomadTimeout("internal_ADD_ALL();",100,"Agregando Todo..."); }
function DEL_ALL() { NomadTimeout("internal_DEL_ALL();",100,"Quitando Todo..."); }
function ADD()     { NomadTimeout("internal_ADD();"    ,100,"Agregando los Seleccionados..."); }        
function DEL()     { NomadTimeout("internal_DEL();"    ,100,"Quitando los Seleccionados..."); }        


function internal_ADD_ALL()
{
	//Limpio los check de las listas
	if (Ctrl("list1arr")) Ctrl("list1arr").DelAllRow();
	if (Ctrl("list2arr")) Ctrl("list2arr").DelAllRow();

	//Agrego los Registros
	//if (Ctrl("list1arr")) for (key in arrB) Ctrl("list1arr").AddRow().SetAttr("id",key.substr(1));
	union(arrA, arrB);
	arrB = new Array();


	//Actualizo las Listas
	refreshList("list1", arrA);
	refreshList("list2", arrB);
}

function internal_DEL_ALL()
{
	//Limpio los check de las listas
	if (Ctrl("list2arr"))
	if (Ctrl("list2arr")) Ctrl("list2arr").DelAllRow();

	//Agrego los Registros
	//if (Ctrl("list2arr")) for (key in arrA) Ctrl("list2arr").AddRow().SetAttr("id",key.substr(1));
	union(arrB, arrA);
	arrA = new Array();

	//Actualizo las Listas
	refreshList("list1", arrA);
	refreshList("list2", arrB);
}

function internal_ADD()
{      
	var MyID;

	//Limpio los check de la lista 1
	if (Ctrl("list1arr"))
		Ctrl("list1arr").DelAllRow();

	if (Ctrl("list2arr") && Ctrl("list2arr").CountRow()>0)
	{ //Caso que hay esta checkeado elementos en la lista

		while(Ctrl("list2arr").CountRow()>0)
		{                                
			//Obtengo el ID del Elemento		
			MyID=Ctrl("list2arr").GetRow(0).GetAttr("id");

			//Agrego el Elemento a la Lista
			arrA["k"+MyID]=arrB["k"+MyID];	
			if (Ctrl("list1arr"))
				Ctrl("list1arr").AddRow().SetAttr("id",MyID);

			//Elimino el Elemento
			if (Ctrl("list2arr"))
				Ctrl("list2arr").DelRow(0);
			delete arrB["k"+MyID];
		}
	} else
	{ //Caso que no hay checkeado elementos en la lista

		//Obtengo el ID del Elemento		
		MyID=Ctrl("list2").GetXValue();

		//Agrego el Elemento a la Lista
		arrA["k"+MyID]=arrB["k"+MyID];	
		if (Ctrl("list1arr"))
			Ctrl("list1arr").AddRow().SetAttr("id",MyID);

		//Elimino el Elemento
		if (Ctrl("list2arr"))
			Ctrl("list2arr").DelRowByAttr("id", MyID);
		delete arrB["k"+MyID];
	}

	//Actualizo las Listas
	refreshList("list1", arrA);
	refreshList("list2", arrB);
}

function internal_DEL()
{
	var MyID;

	//Limpio los check de la lista 2
	if (Ctrl("list2arr"))
		Ctrl("list2arr").DelAllRow();

	if (Ctrl("list1arr") && Ctrl("list1arr").CountRow()>0)
	{ //Caso que hay esta checkeado elementos en la lista
		while(Ctrl("list1arr").CountRow()>0)
		{                                
			//Obtengo el ID del Elemento		
			MyID=Ctrl("list1arr").GetRow(0).GetAttr("id");

			//Agrego el Elemento a la Lista
			arrB["k"+MyID]=arrA["k"+MyID];	
			if (Ctrl("list2arr"))
				Ctrl("list2arr").AddRow().SetAttr("id",MyID);

			//Elimino el Elemento
			if (Ctrl("list1arr"))
				Ctrl("list1arr").DelRow(0);
			delete arrA["k"+MyID];
		}
	} else
	{ //Caso que no hay checkeado elementos en la lista

		//Obtengo el ID del Elemento		
		MyID=Ctrl("list1").GetXValue();

		//Agrego el Elemento a la Lista
		arrB["k"+MyID]=arrA["k"+MyID];	
		if (Ctrl("list2arr"))
			Ctrl("list2arr").AddRow().SetAttr("id",MyID);

		//Elimino el Elemento
		if (Ctrl("list1arr"))
			Ctrl("list1arr").DelRowByAttr("id", MyID);
		delete arrA["k"+MyID];
	}

	//Actualizo las Listas
	refreshList("list1", arrA);
	refreshList("list2", arrB);
}

//Limpio la Lista 1
function clear_list1()
{
	arrA = new Array();
	if (Ctrl("list1arr")) Ctrl("list1arr").DelAllRow();
	refreshList("list1", arrA);
}

//desmarco la Lista 1
function unmark_list1()
{
	if (Ctrl("list1arr")) Ctrl("list1arr").DelAllRow();
	refreshList("list1", arrA);
}

//Elimino la Lista 1
function del_list1()
{
	var MyID;

	if (Ctrl("list1arr") && Ctrl("list1arr").CountRow()>0)
	{ //Caso que hay esta checkeado elementos en la lista
		while(Ctrl("list1arr").CountRow()>0)
		{                                
			//Obtengo el ID del Elemento		
			MyID=Ctrl("list1arr").GetRow(0).GetAttr("id");

			//Elimino el Elemento
			if (Ctrl("list1arr"))
				Ctrl("list1arr").DelRow(0);
			delete arrA["k"+MyID];
		}
	} else
	{ //Caso que no hay checkeado elementos en la lista

		//Obtengo el ID del Elemento		
		MyID=Ctrl("list1").GetXValue();

		//Elimino el Elemento
		if (Ctrl("list1arr"))
			Ctrl("list1arr").DelRowByAttr("id", MyID);
		delete arrA["k"+MyID];
	}

	refreshList("list1", arrA);
}

//Limpio la Lista 2
function clear_list2()
{                          
	var arrDel = new Array();
	for (var key in arrB) {        
		var name = key.substr(1);
		var deleterow = Ctrl("list2arr").GetRowByAttr("id",name);
		if (deleterow == null)
			arrDel.push(key);	
	}
	for (var i=0; i<arrDel.length; i++)
		delete arrB[arrDel[i]];
	refreshList("list2", arrB);
}   

//elimino la Lista 2
function del_list2()
{
	var MyID;

	if (Ctrl("list2arr") && Ctrl("list2arr").CountRow()>0)
	{ //Caso que hay esta checkeado elementos en la lista

		while(Ctrl("list2arr").CountRow()>0)
		{                                
			//Obtengo el ID del Elemento		
			MyID=Ctrl("list2arr").GetRow(0).GetAttr("id");

			//Elimino el Elemento
			if (Ctrl("list2arr"))
				Ctrl("list2arr").DelRow(0);
			delete arrB["k"+MyID];
		}
	} else
	{ //Caso que no hay checkeado elementos en la lista

		//Obtengo el ID del Elemento		
		MyID=Ctrl("list2").GetXValue();

		//Elimino el Elemento
		if (Ctrl("list2arr"))
			Ctrl("list2arr").DelRowByAttr("id", MyID);
		delete arrB["k"+MyID];
	}

	refreshList("list2", arrB);
}

//desmarco la Lista 2
function unmark_list2()
{              
	if (Ctrl("list2arr")) Ctrl("list2arr").DelAllRow();     
	refreshList("list2", arrB);
}

//Envio el XML al Server
function sendToServer()
{
	proxy=new NomadProxy();
	proxy.StoreService().SetSessionStore("IDsCV", array2string(arrA));
	return true;
}

function ACCEPT()
{
	sendToServer();
}

function CANCEL()
{
	Ctrl("main").DoEvent("CANCEL");
}
function SendToServer()
{       
	GetProxy().StoreService().SetUserStore("IDsCV", array2stringcustom(arrB, "ROWS", "ROW"));
	return true;
}

function enable_custom_buttons()
{
	if (Ctrl("list2"))
		CtrlEnabled("btnFILTER", Ctrl("list2").TotalRowsCount()?true:false);
}

