			for $r in sql('
	SELECT 
		COUNT(POS01_CV.oi_cv) as cant_reg

	FROM 
		POS01_CV
		{%?('##oi_idioma##'!='') {% ,POS01_IDIOMAS_CV %} {% %} %}
		{%?('##oi_conocimiento##'!='') {% ,POS01_CONOC_CV%} {% %} %}
	WHERE 1=1					

		{%?('##d_apellido##'!='') {% and contain(POS01_CV.d_apellido, \'##d_apellido##\') %} {% %} %}
		{%?('##d_nombres##'!='') {% and contain(POS01_CV.d_nombres, \'##d_nombres##\') %} {% %} %}
		{%?('##c_nro_doc##'!='') {% and contain(POS01_CV.c_nro_doc, \'##c_nro_doc##\') %} {% %} %}			
		{%?('##c_sexo##'!='') {% and POS01_CV.c_sexo = \'##c_sexo##\' %} {% %} %}
		{%?('##oi_provincia##'!='') {% and POS01_CV.oi_provincia = \'##oi_provincia##\' %} {% %} %}
		{%?('##d_localidad##'!='') {% and contain(POS01_CV.d_localidad, \'##d_localidad##\') %} {% %} %}			
		{%?('##h_edad_desde##'!='') {% and POS01_CV.f_nacim >= {Datetime(\'##h_edad_desde##\')} %} {% %} %}
		{%?('##h_edad_hasta##'!='') {% and POS01_CV.f_nacim <= {Datetime(\'##h_edad_hasta##\')} %} {% %} %}

	{%?('##foto##'!='') 
		{% 
			{%? ('##foto##'='1')
				{% and POS01_CV.oi_foto!=\'\'  and not(isnull(POS01_CV.oi_foto))  %}
				{% and POS01_CV.oi_foto=\'\' or isnull(POS01_CV.oi_foto)  %}
			%}
		%}
		{% %}
	%}

	{%?('##ingreso##'!='') 
		{% 
			{%? ('##ingreso##'='WEB')
				{% and POS01_CV.l_alta_web=1 %}
				{% and POS01_CV.l_alta_web=0 %}
			%}   
		%}
		{% %}
	%}

	{%?('##c_estado##'!='') 
		{% and POS01_CV.c_estado = \'##c_estado##\' %}
		{% %} 
	%}

	{%?('##oi_oferta_lab##'!='') 
		{% and POS01_CV.oi_cv in (SELECT POS01_POSTU_CV.oi_cv
															FROM POS01_POSTU_CV
															WHERE POS01_POSTU_CV.oi_oferta_lab = \'##oi_oferta_lab##\')				
		%} 
		{% %} 
	%} 

	{%?('##oi_idioma##'!='') 
		{% and POS01_IDIOMAS_CV.oi_cv = POS01_CV.oi_cv
	 	   and POS01_IDIOMAS_CV.oi_idioma = \'##oi_idioma##\' %}
		{% %} 
	%} 

	{%?('##c_nivel##'!='') 
		{% and POS01_CONOC_CV.c_nivel = \'##c_nivel##\' %}
		{% %} 
	%}	
	{%?('##oi_conocimiento##'!='') 
		{% and POS01_CONOC_CV.oi_conocimiento = \'##oi_conocimiento##\' %}
		{% %} 
	%}

	{%?('##oi_color_ojos##'!='') {% and POS01_CV.oi_color_ojos = \'##oi_color_ojos##\' %} {% %} %}
			{%?('##oi_color_pelo##'!='') {% and POS01_CV.oi_color_pelo = \'##oi_color_pelo##\' %} {% %} %}			

			{%?('##c_cadera##'!='') {% and POS01_CV.c_cadera = \'##c_cadera##\' %} {% %} %}
			{%?('##c_cintura##'!='') {% and POS01_CV.c_cintura = \'##c_cintura##\' %} {% %} %}			
			{%?('##c_altura##'!='') {% and POS01_CV.c_altura = \'##c_altura##\' %} {% %} %}
			{%?('##c_peso##'!='') {% and POS01_CV.c_peso = \'##c_peso##\' %} {% %} %}
			{%?('##c_busto##'!='') {% and POS01_CV.c_busto = \'##c_busto##\' %} {% %} %}
')/ROWS/ROW
